import React, { useState, useEffect } from 'react';
import { Chip, ScrollShadow } from '@heroui/react';
import { TrendingUp, Video, Play } from 'lucide-react';
import { GENRE_TAGS, getArtwork, searchVideos } from '../services/itunesApi';

export default function RightPanel({ onGenreClick, currentTrack, onOpenDrawer }) {
    const [videos, setVideos] = useState([]);

    useEffect(() => {
        const fetchVideos = async () => {
            try {
                // Fetch some general popular music videos to show
                const results = await searchVideos('taylor swift', 5);
                setVideos(results);
            } catch (error) {
                console.error("Error fetching recommended videos:", error);
            }
        };
        fetchVideos();
    }, []);
    return (
        <div className="flex flex-col h-full overflow-hidden">
            <ScrollShadow className="flex-1 p-4 space-y-6 overflow-y-auto">
                {/* Genre Tags */}
                <div>
                    <div className="flex items-center gap-2 mb-3">
                        <TrendingUp size={16} className="text-theme-400" />
                        <h3 className="text-sm font-semibold">Trending Tags</h3>
                    </div>
                    <div className="flex flex-wrap gap-2">
                        {GENRE_TAGS.map((tag) => (
                            <Chip
                                key={tag.name}
                                variant="flat"
                                size="sm"
                                className={`cursor-pointer bg-gradient-to-r ${tag.color} bg-opacity-10 text-white/90 border-0 hover:opacity-80 transition-opacity px-2`}
                                onClick={() => onGenreClick(tag.name)}
                            >
                                <span className="mr-1">{tag.emoji}</span>
                                {tag.name}
                            </Chip>
                        ))}
                    </div>
                </div>

                {/* Recommended Videos */}
                {videos.length > 0 && (
                    <div className="pt-2">
                        <div className="flex items-center justify-between mb-3">
                            <div className="flex items-center gap-2">
                                <Video size={16} className="text-theme-400" />
                                <h3 className="text-sm font-semibold">Music Videos</h3>
                            </div>
                        </div>
                        <ScrollShadow orientation="horizontal" className="flex gap-4 pb-4 snap-x custom-scrollbar">
                            {videos.map((video) => (
                                <div
                                    key={video.trackId}
                                    className="w-48 flex-shrink-0 snap-start group cursor-pointer"
                                    onClick={() => window.open(video.trackViewUrl, '_blank')}
                                >
                                    <div className="relative aspect-video rounded-xl overflow-hidden shadow-lg mb-2">
                                        <img
                                            src={getArtwork(video.artworkUrl100, 400)}
                                            alt={video.trackName}
                                            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                                            loading="lazy"
                                        />
                                        <div className="absolute inset-0 bg-black/20 group-hover:bg-black/40 transition-colors flex items-center justify-center">
                                            <div className="w-10 h-10 rounded-full bg-white/20 backdrop-blur-md flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity transform group-hover:scale-110">
                                                <Play fill="white" size={16} className="ml-1" />
                                            </div>
                                        </div>
                                        <div className="absolute bottom-1.5 right-1.5 px-2 py-0.5 bg-black/70 text-white text-[10px] font-medium rounded">
                                            Video
                                        </div>
                                    </div>
                                    <p className="text-sm font-semibold truncate group-hover:text-theme-300 transition-colors">
                                        {video.trackName}
                                    </p>
                                    <p className="text-xs text-default-400 truncate mt-0.5">
                                        {video.artistName}
                                    </p>
                                </div>
                            ))}
                        </ScrollShadow>
                    </div>
                )}

                {/* Now Playing Card */}
                {currentTrack && (
                    <div
                        className="glass-card p-3 ambient-glow cursor-pointer hover:bg-white/10 transition-colors group"
                        onClick={onOpenDrawer}
                    >
                        <p className="text-[10px] uppercase tracking-wider text-theme-400 font-semibold mb-2 flex items-center justify-between">
                            <span>Now Playing</span>
                            <span className="opacity-0 group-hover:opacity-100 transition-opacity">Show Queue</span>
                        </p>
                        <img
                            src={getArtwork(currentTrack.artworkUrl100, 500)}
                            alt={currentTrack.trackName}
                            className="w-full aspect-square rounded-xl object-cover mb-3"
                            loading="lazy"
                        />
                        <p className="text-sm font-semibold truncate">{currentTrack.trackName}</p>
                        <p className="text-xs text-default-400 truncate">{currentTrack.artistName}</p>
                        {currentTrack.collectionName && (
                            <p className="text-[10px] text-default-500 truncate mt-0.5">{currentTrack.collectionName}</p>
                        )}

                        {/* Playing indicator */}
                        <div className="flex items-center gap-2 mt-3">
                            <div className="playing-indicator text-theme-400">
                                <span></span><span></span><span></span><span></span>
                            </div>
                            <span className="text-[10px] text-theme-400 font-medium">Playing</span>
                        </div>
                    </div>
                )}
            </ScrollShadow>
        </div>
    );
}
